#!/usr/bin/env bash
set -euo pipefail

# LLM Attribution: Generated by Cursor (auto)

# Upload JUnit zip bundles (from gather-test-reports.sh) to Report Portal and wait for each
# import to finish processing. Requires curl and jq.
#
# Environment:
#   REPORT_PORTAL_URL   Base URL (no trailing slash required)
#   RP_TOKEN            Report Portal API token
#   RP_PROJECT          Project name (slug) in Report Portal
#   REPORTS_PATH        Root directory to search for *.zip (default: test-output)
#   REPORT_PATH         If set, upload only this file (must exist); REPORTS_PATH search is skipped
#   INITIAL_WAIT_TIME   Seconds to wait after import before resolving the launch (default: 60)
#   POLL_INTERVAL       Seconds between status polls (default: 20)
#   MAX_POLL_ATTEMPTS   Max status polls per upload after launch id is known (default: 40)
#   LAUNCH_LOOKUP_ATTEMPTS  Max tries to resolve numeric launch id after import (default: 30)

usage() {
  cat <<'EOF'
Usage: upload-test-reports.sh [--help]

Upload every *.zip under REPORTS_PATH (or a single REPORT_PATH) to Report Portal via the JUnit
import plugin, then wait until each launch is no longer IN_PROGRESS.

Required environment: REPORT_PORTAL_URL, RP_TOKEN, RP_PROJECT

See script header for optional variables and defaults.
EOF
}

err() {
  echo "[$(date +'%Y-%m-%dT%H:%M:%S%z')]: $*" >&2
}

info() {
  echo "[$(date +'%Y-%m-%dT%H:%M:%S%z')]: $*"
}

TMPDIR_WORK=$(mktemp -d)
trap 'rm -rf "$TMPDIR_WORK"' EXIT

require_cmds() {
  local missing=()
  local c
  for c in curl jq; do
    command -v "$c" >/dev/null 2>&1 || missing+=("$c")
  done
  if [[ ${#missing[@]} -gt 0 ]]; then
    err "missing required command(s): ${missing[*]}"
    exit 1
  fi
}

while [[ $# -gt 0 ]]; do
  case "$1" in
    -h | --help)
      usage
      exit 0
      ;;
    *)
      err "unknown option: $1"
      usage >&2
      exit 1
      ;;
  esac
done

: "${REPORT_PORTAL_URL:?REPORT_PORTAL_URL is required}"
: "${RP_TOKEN:?RP_TOKEN is required}"
: "${RP_PROJECT:?RP_PROJECT is required}"

REPORTS_PATH="${REPORTS_PATH:-test-output}"
INITIAL_WAIT_TIME="${INITIAL_WAIT_TIME:-60}"
POLL_INTERVAL="${POLL_INTERVAL:-20}"
MAX_POLL_ATTEMPTS="${MAX_POLL_ATTEMPTS:-40}"
LAUNCH_LOOKUP_ATTEMPTS="${LAUNCH_LOOKUP_ATTEMPTS:-30}"

# Strip trailing slash for predictable joins
RP_BASE="${REPORT_PORTAL_URL%/}"

find_report_zips() {
  find "${REPORTS_PATH}" -type f -name '*.zip' 2>/dev/null | LC_ALL=C sort
}

# POST multipart; print launch UUID to stdout on success
import_junit_zip() {
  local zip_path="$1"
  local response http_code uuid

  response="${TMPDIR_WORK}/import-response.json"
  # Do not set Content-Type manually: curl must set multipart boundary for -F.
  http_code=$(
    curl -sS -w '%{http_code}' -o "$response" \
      "${RP_BASE}/api/v1/plugin/${RP_PROJECT}/junit/import" \
      -H "Authorization: bearer ${RP_TOKEN}" \
      -H 'Accept: application/json' \
      -X POST \
      -F "file=@${zip_path}"
  )

  if [[ "$http_code" != "200" && "$http_code" != "201" ]]; then
    err "import failed for ${zip_path} (HTTP ${http_code})"
    cat "$response" >&2 || true
    return 1
  fi

  uuid=$(jq -r '(.data.id // .data.uuid // .id // .uuid // empty)' < "$response")

  if [[ -z "$uuid" || "$uuid" == "null" ]]; then
    err "could not parse launch UUID from import response for ${zip_path}"
    return 1
  fi
  printf '%s' "$uuid"
}

# Try GET /launch/uuid/{uuid} then GET /launch/latest?filter.eq.uuid=
try_get_launch_id() {
  local uuid="$1"
  local raw http_code body id

  raw=$(
    curl -sS -w '\n%{http_code}' \
      "${RP_BASE}/api/v1/${RP_PROJECT}/launch/uuid/${uuid}" \
      -H "Authorization: bearer ${RP_TOKEN}" \
      -H 'Accept: application/json'
  ) || true
  http_code="${raw##*$'\n'}"
  body="${raw%$'\n'*}"

  if [[ "$http_code" == "200" ]]; then
    id=$(jq -r 'if type == "object" then (.id // .content.id // empty) else empty end' <<< "$body")
    if [[ -n "$id" && "$id" != "null" ]]; then
      printf '%s' "$id"
      return 0
    fi
  fi

  raw=$(
    curl -sS -w '\n%{http_code}' -G \
      "${RP_BASE}/api/v1/${RP_PROJECT}/launch/latest" \
      --data-urlencode "filter.eq.uuid=${uuid}" \
      -H "Authorization: bearer ${RP_TOKEN}" \
      -H 'Accept: application/json'
  ) || true
  http_code="${raw##*$'\n'}"
  body="${raw%$'\n'*}"

  if [[ "$http_code" == "200" ]]; then
    id=$(
      jq -r '
        if .content and (.content | type == "array") and (.content | length > 0) then .content[0].id
        elif type == "array" and length > 0 then .[0].id
        else empty end
      ' <<< "$body"
    )
    if [[ -n "$id" && "$id" != "null" ]]; then
      printf '%s' "$id"
      return 0
    fi
  fi

  return 1
}

wait_for_launch_id() {
  local uuid="$1"
  local attempt=0 launch_id=""

  while [[ $attempt -lt "$LAUNCH_LOOKUP_ATTEMPTS" ]]; do
    sleep 5
    if launch_id=$(try_get_launch_id "$uuid"); then
      printf '%s' "$launch_id"
      return 0
    fi
    attempt=$((attempt + 1))
  done

  err "timed out resolving numeric launch id for import uuid ${uuid}"
  return 1
}

# Parse GET .../launch/status response; fall back to empty
extract_status_from_status_endpoint() {
  local body="$1"
  jq -r '
    if type == "array" and length > 0 then .[0].status
    elif .content and (.content | type == "array") and (.content | length > 0) then .content[0].status
    elif .status then .status
    else empty end
  ' <<< "$body"
}

# GET /launch/{id} when /launch/status shape differs between Report Portal versions
fetch_launch_status_fallback() {
  local launch_id="$1"
  curl -sS \
    "${RP_BASE}/api/v1/${RP_PROJECT}/launch/${launch_id}" \
    -H "Authorization: bearer ${RP_TOKEN}" \
    -H 'Accept: application/json'
}

poll_until_not_in_progress() {
  local launch_id="$1"
  local attempt=0
  local body st

  while [[ $attempt -lt "$MAX_POLL_ATTEMPTS" ]]; do
    if [[ $attempt -eq 0 ]]; then
      sleep "${INITIAL_WAIT_TIME}"
    else
      sleep "${POLL_INTERVAL}"
    fi

    body=$(
      curl -sS -G \
        "${RP_BASE}/api/v1/${RP_PROJECT}/launch/status" \
        --data-urlencode "ids=${launch_id}" \
        -H "Authorization: bearer ${RP_TOKEN}" \
        -H 'Accept: application/json'
    )

    st=$(extract_status_from_status_endpoint "$body")
    if [[ -z "$st" || "$st" == "null" ]]; then
      st=$(
        fetch_launch_status_fallback "$launch_id" | jq -r '.status // empty'
      )
    fi

    if [[ -z "$st" || "$st" == "null" ]]; then
      err "could not read launch status (attempt $((attempt + 1))/${MAX_POLL_ATTEMPTS}); raw: ${body:0:500}"
    elif [[ "$st" != "IN_PROGRESS" ]]; then
      info "launch ${launch_id} finished with status ${st}"
      return 0
    else
      info "launch ${launch_id} still ${st} (poll $((attempt + 1))/${MAX_POLL_ATTEMPTS})"
    fi
    attempt=$((attempt + 1))
  done

  err "timed out waiting for launch ${launch_id} to leave IN_PROGRESS"
  return 1
}

upload_and_wait_one() {
  local zip_path="$1"
  local uuid launch_id

  info "uploading ${zip_path}"
  uuid=$(import_junit_zip "$zip_path")
  info "import accepted, launch UUID ${uuid}"

  launch_id=$(wait_for_launch_id "$uuid")
  info "resolved launch id ${launch_id}"

  poll_until_not_in_progress "$launch_id"
}

#################
## Main Script ##
#################
require_cmds

zips=()

if [[ -n "${REPORT_PATH:-}" ]]; then
  [[ -f "$REPORT_PATH" ]] || {
    err "REPORT_PATH is not a file: ${REPORT_PATH}"
    exit 1
  }
  zips=("$REPORT_PATH")
else
  [[ -d "$REPORTS_PATH" ]] || {
    err "REPORTS_PATH is not a directory: ${REPORTS_PATH}"
    exit 1
  }
  mapfile -t zips < <(find_report_zips)
  if [[ ${#zips[@]} -eq 0 ]]; then
    err "no .zip files under ${REPORTS_PATH}"
    exit 1
  fi
fi

for z in "${zips[@]}"; do
  upload_and_wait_one "$z"
done

info "all uploads completed"

